import { describe, it, expect } from 'vitest';

// Assume the function is exported from the same module
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  it('should handle happy path – sorts notes by updatedAt descending', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01') },
      { id: 2, updatedAt: new Date('2023-03-01') },
      { id: 3, updatedAt: new Date('2023-02-01') },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 2, updatedAt: new Date('2023-03-01') },
      { id: 3, updatedAt: new Date('2023-02-01') },
      { id: 1, updatedAt: new Date('2023-01-01') },
    ]);
  });

  it('should handle edge case – notes with identical updatedAt timestamps', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01T10:00:00Z') },
      { id: 2, updatedAt: new Date('2023-01-01T10:00:00Z') },
      { id: 3, updatedAt: new Date('2022-12-31T23:59:59Z') },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted[0].id).toBe(1); // first two with same timestamp keep original order
    expect(sorted[1].id).toBe(2);
    expect(sorted[2].id).toBe(3);
  });

  it('should handle null/empty inputs – returns empty array for undefined, null, or empty array', () => {
    const resultUndefined = sortNotesByUpdatedAt(undefined as any);
    const resultNull = sortNotesByUpdatedAt(null as any);
    const resultEmpty = sortNotesByUpdatedAt([]);

    expect(resultUndefined).toEqual([]);
    expect(resultNull).toEqual([]);
    expect(resultEmpty).toEqual([]);
  });
});

